# UNSAFE: deserializing user-supplied data with pickle
import pickle
from flask import request

@app.route('/process', methods=['POST'])
def process():
    data = request.get_data()
    obj = pickle.loads(data)  # RCE if attacker controls data
    return str(obj)

safe_example:
# SAFE: use JSON for untrusted data deserialization
import json
from flask import request

@app.route('/process', methods=['POST'])
def process():
    data = request.get_data()
    obj = json.loads(data)  # JSON cannot execute code
    return str(obj)

# SAFE: use yaml.safe_load for YAML input
import yaml

def parse_config(yaml_string):
    return yaml.safe_load(yaml_string)  # Rejects Python-specific tags
